// Example file to analyze: user-service.ts

// BUG 1: Critical - Null pointer exception
function getUserData(userId: string) {
  const user = users.find(u => u.id === userId);
  return user.name; // Will crash if user is undefined
}

// BUG 2: High - Unhandled promise rejection
async function fetchUser(userId: string) {
  const response = await fetch(`/api/users/${userId}`);
  // Missing error handling for failed requests
  return response.json();
}

// BUG 3: Medium - Memory leak in React component
function UserProfile({ userId }) {
  useEffect(() => {
    const interval = setInterval(() => {
      // Update user data
    }, 5000);
    // Missing cleanup - memory leak!
  }, [userId]);
}

// BUG 4: Low - Inefficient algorithm
function findDuplicates(arr: number[]): number[] {
  const duplicates: number[] = [];
  for (let i = 0; i < arr.length; i++) {
    for (let j = i + 1; j < arr.length; j++) {
      if (arr[i] === arr[j]) {
        duplicates.push(arr[i]);
      }
    }
  }
  return duplicates;
}

