// Example file: service.ts

// CODE SMELL 1: Long method
function processOrder(order: Order) {
  // Validate order
  if (!order.items || order.items.length === 0) {
    throw new Error("No items");
  }

  // Calculate total
  let total = 0;
  for (const item of order.items) {
    total += item.price * item.quantity;
  }

  // Apply discounts
  if (order.coupon) {
    total *= (1 - order.coupon.discount);
  }

  // Calculate tax
  const tax = total * 0.08;
  total += tax;

  // Save to database
  db.saveOrder({ ...order, total, tax });

  // Send confirmation email
  emailService.sendConfirmation(order.customer.email, total);

  // Update inventory
  for (const item of order.items) {
    inventory.update(item.id, -item.quantity);
  }

  // Log transaction
  logger.info(`Order ${order.id} processed: $${total}`);
}

// CODE SMELL 2: Deep nesting
function validateUser(user: User) {
  if (user) {
    if (user.isActive) {
      if (user.hasPermission) {
        if (user.emailVerified) {
          return true;
        }
      }
    }
  }
  return false;
}

