// CODE SMELL 4: Tight coupling
class OrderService {
  private db: Database;
  private email: EmailService;
  private inventory: InventoryService;

  constructor() {
    this.db = new Database();
    this.email = new EmailService();
    this.inventory = new InventoryService();
  }
}

      // Example file: auth.ts

      // SECURITY ISSUE 1: SQL Injection
      function getUser(username: string, password: string) {
        const query = `SELECT * FROM users WHERE username = '${username}' AND password = '${password}'`;
        return db.query(query);
      }

      // SECURITY ISSUE 2: XSS Vulnerability
      function displayUserComment(comment: string) {
        return `
${comment}`; // No sanitization
      }

      // SECURITY ISSUE 3: Insecure password storage
      function storePassword(password: string) {
        // Storing plain text password
        db.save({ password });
      }

      // SECURITY ISSUE 4: Missing rate limiting
      async function login(username: string, password: string) {
        // No rate limiting - vulnerable to brute force
        const user = await authenticate(username, password);
        return user;
      }

      // SECURITY ISSUE 5: Insecure direct object reference
      function getUserData(userId: string) {
        // No authorization check
        return db.getUser(userId);
      }

      // GOOD EXAMPLES
      function getUser(username: string, password: string) {
        const query = 'SELECT * FROM users WHERE username = ? AND password = ?';
        return db.query(query, [username, password]);
      }

      function displayUserComment(comment: string) {
        const sanitized = sanitizeHtml(comment);
        return `
${sanitized}`;
      }

      async function storePassword(password: string) {
        const hashed = await bcrypt.hash(password, 12);
        db.save({ password: hashed });
      }

      async function login(username: string, password: string) {
        // With rate limiting
        await rateLimiter.check(username);
        const user = await authenticate(username, password);
        return user;
      }

      async function getUserData(userId: string, currentUserId: string) {
        // With authorization check
        if (userId !== currentUserId) {
          throw new Error("Unauthorized");
        }
        return db.getUser(userId);
      }
